(() => {
  let s = $('Webhook').item.json.body.data.purchase.origin.sck || "";
  s = s.replaceAll(" — Cópia", "").trim();

  if (!s) return "";

  // Se já vier estruturado, só limpa espaços
  if (s.includes("||")) {
    return s.split("||").map(v => (v || "").trim()).join("||");
  }

  // Source aceitos
  const sources = [
    "ig",
    "fb",
    "ytv",
    "ttk",
    "an",
    "msg",
    "g",
    "s"
  ];

  // Medium aceitos
  const mediums = [
    "Instagram_Explore_Grid_Home",
    "Facebook_Mobile_Feed",
    "Facebook_Mobile_Reels",
    "Instagram_Stories",
    "Instagram_Explore",
    "Instagram_Reels",
    "Instagram_Feed",
    "Facebook_Stories",
    "\{\{placement\}\}"
  ];

  // Ordena do maior para o menor pra evitar match parcial errado
  const orderedMediums = [...mediums].sort((a, b) => b.length - a.length);

  let utm_source = "";
  let utm_medium = "";
  let utm_campaign = "";
  let utm_term = "";
  let utm_content = "";

  // 1. source
  for (const src of sources) {
    if (s.toLowerCase().startsWith(src.toLowerCase())) {
      utm_source = src;
      s = s.slice(src.length);
      break;
    }
  }

  if (!utm_source) return s;

  // 2. medium
  for (const med of orderedMediums) {
    if (s.startsWith(med)) {
      utm_medium = med;
      s = s.slice(med.length);
      break;
    }
  }

  // fallback bruto caso medium não seja reconhecido
  if (!utm_medium) {
    const mediumMatch = s.match(/^([A-Za-z_{}]+)(?=\[)/);
    if (mediumMatch) {
      utm_medium = mediumMatch[1];
      s = s.slice(utm_medium.length);
    }
  }

  if (!utm_medium) {
    return [utm_source, s].filter(Boolean).join("||");
  }

  // 3. campaign
  // começa no primeiro [
  // termina antes do padrão dd[AUTO]... ou dd[algo]
  // exemplo:
  // [VDPABR26] ... 2026.03.09  -> campaign
  // 00[AUTO]...               -> term
  const termStartMatch = s.match(/(\d{2}\[[^\]]+\])/);

  if (termStartMatch && typeof termStartMatch.index === "number") {
    const idx = termStartMatch.index;

    utm_campaign = s.slice(0, idx).trim();
    s = s.slice(idx);
  } else {
    // fallback pela data colada com 2 dígitos
    const datePlusDigits = s.match(/(\d{4}\.\d{2}\.\d{2})(\d{2}\[)/);
    if (datePlusDigits && typeof datePlusDigits.index === "number") {
      const idx = datePlusDigits.index;
      utm_campaign = s.slice(0, idx) + datePlusDigits[1];
      s = s.slice(idx + datePlusDigits[1].length);
    } else {
      // não conseguiu separar term/content
      return [utm_source, utm_medium, s].filter(Boolean).join("||");
    }
  }

  s = s.trim();

  // 4. content
  // normalmente começa em [ADxx]
  const contentMatch = s.match(/\[AD\d+\]/i);

  if (contentMatch && typeof contentMatch.index === "number") {
    const idx = contentMatch.index;
    utm_term = s.slice(0, idx).trim();
    utm_content = s.slice(idx).trim();
  } else {
    utm_term = s.trim();
  }

  return [
    utm_source,
    utm_medium,
    utm_campaign,
    utm_term,
    utm_content
  ].map(v => (v || "").trim()).join("||");
})()
}}

